// Tax4Us Podcast Agent - Input Processing
const input = $input.first().json;

// Validate required fields
const required = ['topic', 'duration', 'platform'];
const missing = required.filter(field => !input[field]);
if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

// Process podcast request
const podcastData = {
  topic: input.topic,
  duration: input.duration || '15 minutes',
  platform: input.platform || 'captivate',
  targetAudience: input.targetAudience || 'Israeli business owners',
  language: input.language || 'hebrew',
  episodeType: input.episodeType || 'educational',
  timestamp: new Date().toISOString(),
  status: 'processing'
};

return {
  json: {
    ...podcastData,
    message: 'Podcast request processed successfully',
    nextStep: 'script_generation'
  }
};

parameters.prompt:
Create a comprehensive podcast script for Tax4Us based on the following specifications:

Topic: {{ $json.topic }}
Duration: {{ $json.duration }}
Target Audience: {{ $json.targetAudience }}
Language: {{ $json.language }}
Episode Type: {{ $json.episodeType }}

Requirements:
1. Create a professional, engaging script
2. Include introduction, main content, and conclusion
3. Add natural speaking transitions
4. Include call-to-action for Tax4Us services
5. Optimize for the specified duration
6. Use appropriate tone for the target audience
7. Include relevant examples and case studies

Format the output with clear sections and timing markers.

